Function: check_database_health
Domain: db
Explanation: Checks database connectivity by executing a simple query and returns a health status along with latency metrics.
Docstring: undefined
Source: async def check_database_health() -> dict:
    """Perform a simple database health check."""
    if not AsyncSessionLocal:
        return {
            "healthy": False,
            "error": "Database is disabled",
            "response_time_ms": 0
        }

    import time
    start_time = time.time()

    try:
        async with AsyncSessionLocal() as session:
            from sqlalchemy import text
            result = await session.execute(text("SELECT 1"))
            row = result.fetchone()

            response_time = (time.time() - start_time) * 1000

            if row and row[0] == 1:
                return {
                    "healthy": True,
                    "response_time_ms": round(response_time, 2)
                }
            else:
                return {
                    "healthy": False,
                    "error": "Health check query failed",
                    "response_time_ms": round(response_time, 2)
                }

    except Exception as e:
        response_time = (time.time() - start_time) * 1000
        return {
            "healthy": False,
            "error": str(e),
            "response_time_ms": round(response_time, 2)
        }

