Function: _generate_single_example_output
Domain: general
Explanation: Constructs the Markdown string representing the 'output' part of a CLI documentation example, supporting multiple Python versions, models, and comparisons.
Docstring: Generate output section for a single example.
Source: def _generate_single_example_output(example: CLIDocExample, prefix: str = "    ") -> str:
    """Generate output section for a single example."""
    md = ""
    if example.expected_stdout:
        stdout_value = example.expected_stdout
        if "/" in stdout_value or stdout_value.endswith((".py", ".txt")):
            try:
                content = read_expected_file(stdout_value)
                md += f"{prefix}```\n"
                for line in content.strip().split("\n"):
                    md += f"{prefix}{line}\n" if line else f"{prefix}\n"
                md += f"{prefix}```\n\n"
            except (FileNotFoundError, ValueError) as e:
                md += f"{prefix}> **Error:** {e}\n\n"
        else:
            md += f"{prefix}```\n"
            for line in stdout_value.strip().split("\n"):
                md += f"{prefix}{line}\n" if line else f"{prefix}\n"
            md += f"{prefix}```\n\n"
    elif example.comparison_output and example.model_outputs:
        model_labels = dict(ORDERED_MODEL_OUTPUT_LABELS)
        for model_key, output_file in validated_model_outputs(example):
            label = model_labels.get(model_key, model_key)
            md += f'{prefix}=== "{label}"\n\n'
            try:
                content = read_expected_file(output_file)
                md += indent_code_block(content, prefix + "    ")
            except (FileNotFoundError, ValueError) as e:
                md += f"{prefix}    > **Error:** {e}\n\n"
        md += f'{prefix}=== "Without Option (Baseline)"\n\n'
        try:
            content = read_expected_file(example.comparison_output)
            md += indent_code_block(content, prefix + "    ")
        except (FileNotFoundError, ValueError) as e:
            md += f"{prefix}    > **Error:** {e}\n\n"
    elif example.comparison_output and example.golden_output:
        md += f'{prefix}=== "With Option"\n\n'
        try:
            content = read_expected_file(example.golden_output)
            md += indent_code_block(content, prefix + "    ")
        except (FileNotFoundError, ValueError) as e:
            md += f"{prefix}    > **Error:** {e}\n\n"
        md += f'{prefix}=== "Without Option"\n\n'
        try:
            content = read_expected_file(example.comparison_output)
            md += indent_code_block(content, prefix + "    ")
        except (FileNotFoundError, ValueError) as e:
            md += f"{prefix}    > **Error:** {e}\n\n"
    elif example.version_outputs:
        sorted_versions = sorted(
            example.version_outputs.items(),
            key=lambda x: tuple(map(int, x[0].split("."))),
        )
        for version, output_file in sorted_versions:
            md += f'{prefix}=== "Python {version}"\n\n'
            try:
                content = read_expected_file(output_file)
                md += indent_code_block(content, prefix + "    ")
            except (FileNotFoundError, ValueError) as e:
                md += f"{prefix}    > **Error:** {e}\n\n"
    elif example.model_outputs:
        model_labels = dict(ORDERED_MODEL_OUTPUT_LABELS)
        for model_key, output_file in validated_model_outputs(example):
            label = model_labels.get(model_key, model_key)
            md += f'{prefix}=== "{label}"\n\n'
            try:
                content = read_expected_file(output_file)
                md += indent_code_block(content, prefix + "    ")
            except (FileNotFoundError, ValueError) as e:
                md += f"{prefix}    > **Error:** {e}\n\n"
    elif example.golden_output:
        try:
            content = read_expected_file(example.golden_output)
            md += f"{prefix}```python\n"
            for line in content.strip().split("\n"):
                md += f"{prefix}{line}\n" if line else f"{prefix}\n"
            md += f"{prefix}```\n\n"
        except (FileNotFoundError, ValueError) as e:
            md += f"{prefix}> **Error:** {e}\n\n"
    return md

Function: extract_page_info
Domain: file_io
Explanation: Reads a Markdown file and extracts its main title (H1) and a short description while stripping emojis and code blocks.
Docstring: Extract title and description from a Markdown file.
Source: def extract_page_info(md_path: Path, url: str, depth: int = 0) -> PageInfo | None:
    """Extract title and description from a Markdown file."""
    if not md_path.exists():
        return print(f"Warning: {md_path} not found, skipping", file=sys.stderr)
    try:
        content = md_path.read_text(encoding="utf-8")
    except OSError as e:
        return print(f"Warning: Cannot read {md_path}: {e}", file=sys.stderr)

    title, desc_lines, in_code, found_h1 = md_path.stem.replace("-", " ").replace("_", " ").title(), [], False, False
    for line in content.split("\n"):
        if (s := line.strip()).startswith("```"):
            in_code = not in_code
        elif in_code:
            pass
        elif s.startswith("# ") and not found_h1:
            title, found_h1 = EMOJI_RE.sub("", s[2:]).strip(), True
        elif found_h1:
            if s.startswith("## "):
                break
            if s.startswith(SKIP_PREFIXES) or (not s and desc_lines):
                if not s and desc_lines:
                    break
                continue
            if s:
                desc_lines.append(s)
                if len(desc_lines) >= MAX_DESC_LINES:
                    break

    desc = EMOJI_RE.sub("", " ".join(desc_lines)).strip() if desc_lines else ""
    if len(desc) > MAX_DESC_LEN:
        desc = desc[: MAX_DESC_LEN - 3] + "..."
    return PageInfo(
        title=title, path=str(md_path.relative_to(DOCS_DIR)), url=url, description=desc, content=content, depth=depth
    )

Function: generate_llms_txt
Domain: general
Explanation: Constructs the content for an llms.txt file, organizing links into main and optional sections based on the navigation structure.
Docstring: Generate llms.txt content.
Source: def generate_llms_txt(config: SiteConfig, sections: list[NavSection], pages: list[PageInfo]) -> str:
    """Generate llms.txt content."""
    page_map = {p.path: p for p in pages}

    def fmt(page: PageInfo) -> str:
        return f"- [{page.title}]({page.url})" + (f": {page.description}" if page.description else "")

    def is_optional(path: str | None) -> bool:
        return path is not None and any(fnmatch(path, pat) for pat in OPTIONAL_PATTERNS)

    def render(section: NavSection) -> list[str]:
        if section.path:
            return [fmt(p)] if (p := page_map.get(section.path)) else []
        if not section.children:
            return []
        hdr = "##" if section.depth == 0 else "###"
        lines = [f"{hdr} {section.title}", ""]
        for child in section.children:
            lines.extend(render(child))
        return [*lines, ""]

    main, optional = [], []
    for s in sections:
        is_opt = (s.path and is_optional(s.path)) or (s.children and all(is_optional(c.path) for c in s.children))
        (optional if is_opt else main).append(s)

    lines = [f"# {config['site_name']}", "", f"> {config['site_description']}", ""]
    for s in main:
        lines.extend(render(s))
    if optional:
        lines.extend(["## Optional", ""])
        lines.extend(
            fmt(p)
            for s in optional
            for item in ([s] if s.path else s.children)
            if item.path and (p := page_map.get(item.path))
        )
        lines.append("")

    while lines and not lines[-1]:
        lines.pop()
    return "\n".join([*lines, ""])

Function: _find_future_import_insertion_point
Domain: general
Explanation: Analyzes a Python file header to determine the correct character index for inserting __future__ imports, typically after docstrings.
Docstring: Find position in header where __future__ import should be inserted.
Source: def _find_future_import_insertion_point(header: str) -> int:
    """Find position in header where __future__ import should be inserted."""
    import ast  # noqa: PLC0415

    try:
        tree = ast.parse(header)
    except SyntaxError:
        return 0

    lines = header.splitlines(keepends=True)

    def line_end_pos(line_num: int) -> int:
        return sum(len(lines[i]) for i in range(line_num))

    if not tree.body:
        return len(header)

    first_stmt = tree.body[0]
    is_docstring = isinstance(first_stmt, ast.Expr) and (
        (isinstance(first_stmt.value, ast.Constant) and isinstance(first_stmt.value.value, str))
        or isinstance(first_stmt.value, ast.JoinedStr)
    )
    if is_docstring:
        end_line = first_stmt.end_lineno or len(lines)
        pos = line_end_pos(end_line)
        while end_line < len(lines) and not lines[end_line].strip():
            pos += len(lines[end_line])
            end_line += 1
        return pos

    pos = 0
    for i in range(first_stmt.lineno - 1):
        pos += len(lines[i])
    return pos

Function: _get_pyproject_toml_config
Domain: file_io
Explanation: Searches for a pyproject.toml file in the directory hierarchy and extracts the relevant configuration section for the code generator.
Docstring: Find and return the [tool.datamodel-codegen] section of the closest pyproject.toml if it exists.
Source: def _get_pyproject_toml_config(source: Path, profile: str | None = None) -> dict[str, Any]:
    """Find and return the [tool.datamodel-codegen] section of the closest pyproject.toml if it exists."""
    current_path = source
    while current_path != current_path.parent:
        if (current_path / "pyproject.toml").is_file():
            pyproject_toml = load_toml(current_path / "pyproject.toml")
            if "datamodel-codegen" in pyproject_toml.get("tool", {}):
                tool_config = pyproject_toml["tool"]["datamodel-codegen"]

                base_config: dict[str, Any] = {k: v for k, v in tool_config.items() if k != "profiles"}

                if profile:
                    profiles = tool_config.get("profiles", {})
                    if profile not in profiles:
                        available = list(profiles.keys()) if profiles else "none"
                        msg = f"Profile '{profile}' not found in pyproject.toml. Available profiles: {available}"
                        raise Error(msg)
                    resolved_profile = _resolve_profile_extends(profiles, profile)
                    base_config.update(resolved_profile)

                pyproject_config = {k.replace("-", "_"): v for k, v in base_config.items()}
                if (
                    "capitalize_enum_members" in pyproject_config and "capitalise_enum_members" not in pyproject_config
                ):  # pragma: no cover
                    pyproject_config["capitalise_enum_members"] = pyproject_config.pop("capitalize_enum_members")
                return pyproject_config

        if (current_path / ".git").exists():  # pragma: no cover
            break

        current_path = current_path.parent

    if profile:
        msg = f"Profile '{profile}' requested but no [tool.datamodel-codegen] section found in pyproject.toml"
        raise Error(msg)

    return {}

Function: generate_cli_command
Domain: general
Explanation: Converts a configuration dictionary (typically from pyproject.toml) back into a shell command for the CLI.
Docstring: Generate CLI command from pyproject.toml configuration.
Source: def generate_cli_command(config: dict[str, TomlValue]) -> str:
    """Generate CLI command from pyproject.toml configuration."""
    parts: list[str] = ["datamodel-codegen"]

    for key, value in sorted(config.items()):
        if key in EXCLUDED_CONFIG_OPTIONS:
            continue

        cli_key = key.replace("_", "-")

        if isinstance(value, bool):
            if value:
                parts.append(f"--{cli_key}")
            elif key in BOOLEAN_OPTIONAL_OPTIONS:
                parts.append(f"--no-{cli_key}")
        elif isinstance(value, list):
            parts.extend((f"--{cli_key}", _format_cli_value(cast("list[str]", value))))
        else:
            parts.extend((f"--{cli_key}", _format_cli_value(str(value))))

    return " ".join(parts) + "\n"

Function: main
Domain: general
Explanation: Main entry point for the CLI. It handles argument parsing, configuration loading from pyproject.toml, input validation, and invokes the generation or watch processes.
Docstring: Execute datamodel code generation from command-line arguments.
Source: def main(args: Sequence[str] | None = None) -> Exit:  # noqa: PLR0911, PLR0912, PLR0914, PLR0915
    """Execute datamodel code generation from command-line arguments."""
    vars(namespace).clear()
    namespace.no_color = False

    if "_ARGCOMPLETE" in os.environ:  # pragma: no cover
        import argcomplete  # noqa: PLC0415

        argcomplete.autocomplete(arg_parser)

    if args is None:  # pragma: no cover
        args = sys.argv[1:]

    arg_parser.parse_args(args, namespace=namespace)

    if namespace.version:
        from datamodel_code_generator import get_version  # noqa: PLC0415

        print(get_version())  # noqa: T201
        sys.exit(0)

    if namespace.generate_pyproject_config:
        config_output = generate_pyproject_config(namespace)
        print(config_output)  # noqa: T201
        return Exit.OK

    if namespace.generate_prompt is not None:
        from datamodel_code_generator.prompt import generate_prompt  # noqa: PLC0415

        help_text = arg_parser.format_help()
        prompt_output = generate_prompt(namespace, help_text)
        print(prompt_output)  # noqa: T201
        return Exit.OK

    # Handle --ignore-pyproject and --profile options
    if namespace.ignore_pyproject:
        pyproject_config: dict[str, Any] = {}
    else:
        try:
            pyproject_config = _get_pyproject_toml_config(Path.cwd(), profile=namespace.profile)
        except Error as e:
            print(e.message, file=sys.stderr)  # noqa: T201
            return Exit.ERROR

    if namespace.generate_cli_command:
        if not pyproject_config:
            print(  # noqa: T201
                "No [tool.datamodel-codegen] section found in pyproject.toml",
                file=sys.stderr,
            )
            return Exit.ERROR
        command_output = generate_cli_command(pyproject_config)
        print(command_output)  # noqa: T201
        return Exit.OK

    try:
        config = Config.model_validate(pyproject_config)
        config.merge_args(namespace)
    except Error as e:
        print(e.message, file=sys.stderr)  # noqa: T201
        return Exit.ERROR

    if not config.input and not config.url and not config.input_model and sys.stdin.isatty():
        print(  # noqa: T201
            "Not Found Input: require `stdin` or arguments `--input`, `--url`, or `--input-model`",
            file=sys.stderr,
        )
        arg_parser.print_help()
        return Exit.ERROR

    if config.input_model and (config.input or config.url):
        print(  # noqa: T201
            "Error: --input-model cannot be used with --input or --url",
            file=sys.stderr,
        )
        return Exit.ERROR

    # --url implies --allow-remote-refs since the user is explicitly fetching a remote schema
    if config.url:
        config.allow_remote_refs = True

    if config.check and config.output is None:
        print(  # noqa: T201
            "Error: --check cannot be used with stdout output (no --output specified)",
            file=sys.stderr,
        )
        return Exit.ERROR

    if config.watch and config.check:
        print(  # noqa: T201
            "Error: --watch and --check cannot be used together",
            file=sys.stderr,
        )
        return Exit.ERROR

    if config.watch and config.input_model:
        print(  # noqa: T201
            "Error: --watch cannot be used with --input-model",
            file=sys.stderr,
        )
        return Exit.ERROR

    if config.watch and (config.input is None or is_url(str(config.input))):
        print(  # noqa: T201
            "Error: --watch requires --input file path (not URL or stdin)",
            file=sys.stderr,
        )
        return Exit.ERROR

    if not is_supported_in_black(config.target_python_version):  # pragma: no cover
        print(  # noqa: T201
            f"Installed black doesn't support Python version {config.target_python_version.value}.\n"
            f"You have to install a newer black.\n"
            f"Installed black version: {_get_black().__version__}",
            file=sys.stderr,
        )
        return Exit.ERROR

    if config.debug:  # pragma: no cover
        enable_debug_message()

    if config.disable_warnings:
        warnings.simplefilter("ignore")

    if (
        config.output_model_type in {DataModelType.PydanticV2BaseModel, DataModelType.PydanticV2Dataclass}
        and not config.use_annotated
        and namespace.use_annotated is None
        and pyproject_config.get("use_annotated") is None
    ):
        warnings.warn(
            "Pydantic v2 with --use-annotated is recommended for correct type annotations. "
            "The current default (use_annotated=False) generates constrained types like "
            "'conint(ge=1, le=365)' which are discouraged in Pydantic v2. "
            "In a future version, --use-annotated will be enabled by default for Pydantic v2. "
            "Please explicitly specify --use-annotated or --no-use-annotated.",
            DeprecationWarning,
            stacklevel=1,
        )

    if config.reuse_scope == ReuseScope.Tree and not config.reuse_model:
        print(  # noqa: T201
            "Warning: --reuse-scope=tree has no effect without --reuse-model",
            file=sys.stderr,
        )

    if config.collapse_root_models_name_strategy and not config.collapse_root_models:
        print(  # noqa: T201
            "Error: --collapse-root-models-name-strategy requires --collapse-root-models",
            file=sys.stderr,
        )
        return Exit.ERROR

    if (
        config.use_specialized_enum
        and namespace.use_specialized_enum is not False  # CLI didn't disable it
        and (namespace.use_specialized_enum is True or pyproject_config.get("use_specialized_enum") is True)
        and not config.target_python_version.has_strenum
    ):
        print(  # noqa: T201
            f"Error: --use-specialized-enum requires --target-python-version 3.11 or later.\n"
            f"Current target version: {config.target_python_version.value}\n"
            f"StrEnum is only available in Python 3.11+.",
            file=sys.stderr,
        )
        return Exit.ERROR

    extra_template_data: defaultdict[str, dict[str, Any]] | None
    if config.extra_template_data is None:
        extra_template_data = None
    else:
        with config.extra_template_data as data:
            try:
                extra_template_data = json.load(data, object_hook=lambda d: defaultdict(dict, **d))
            except json.JSONDecodeError as e:
                print(f"Unable to load extra template data: {e}", file=sys.stderr)  # noqa: T201
                return Exit.ERROR

        # Extract additional_imports from extra_template_data entries and merge with config
        assert extra_template_data is not None
        additional_imports_from_template_data = _extract_additional_imports(extra_template_data)
        if additional_imports_from_template_data:
            if config.additional_imports is None:
                config.additional_imports = additional_imports_from_template_data
            else:
                config.additional_imports = list(config.additional_imports) + additional_imports_from_template_data

    def _validate_aliases(data: Any) -> str | None:
        if not isinstance(data, dict) or not all(
            isinstance(k, str) and (isinstance(v, str) or (isinstance(v, list) and all(isinstance(i, str) for i in v)))
            for k, v in data.items()
        ):
            return (
                "must be a JSON mapping with string keys and string or list of strings values "
                '(e.g. {"from": "to", "field": ["alias1", "alias2"]})'
            )
        return None

    def _validate_string_key_dict(data: Any) -> str | None:
        if not isinstance(data, dict) or not all(isinstance(k, str) for k in data):
            return "must be a JSON object with string keys"
        return None

    def _validate_string_mapping(data: Any) -> str | None:
        if not isinstance(data, dict) or not all(isinstance(k, str) and isinstance(v, str) for k, v in data.items()):
            return 'must be a JSON string mapping (e.g. {"key": "value", ...})'
        return None

    aliases, error = _load_json_config(config.aliases, "alias mapping", _validate_aliases)
    if error:
        print(error, file=sys.stderr)  # noqa: T201
        return Exit.ERROR

    default_value_overrides, error = _load_json_config(
        config.default_values, "default values mapping", _validate_string_key_dict
    )
    if error:
        print(error, file=sys.stderr)  # noqa: T201
        return Exit.ERROR

    custom_formatters_kwargs, error = _load_json_config(
        config.custom_formatters_kwargs, "custom_formatters_kwargs mapping", _validate_string_mapping
    )
    if error:
        print(error, file=sys.stderr)  # noqa: T201
        return Exit.ERROR

    validators_config, error = _load_validators_config(config.validators)
    if error:
        print(error, file=sys.stderr)  # noqa: T201
        return Exit.ERROR

    if config.check:
        config_output = cast("Path", config.output)
        is_directory_output = not config_output.suffix
        temp_context: tempfile.TemporaryDirectory[str] | None = tempfile.TemporaryDirectory()
        temp_dir = Path(temp_context.name)
        if is_directory_output:
            generate_output: Path | None = temp_dir / config_output.name
        else:
            generate_output = temp_dir / "output.py"
    else:
        temp_context = None
        generate_output = config.output
        is_directory_output = False

    try:
        input_: Path | str | ParseResult
        if config.input_model:
            from datamodel_code_generator.input_model import Error as InputModelError  # noqa: PLC0415
            from datamodel_code_generator.input_model import load_model_schema  # noqa: PLC0415

            try:
                schema = load_model_schema(
                    config.input_model,
                    config.input_file_type,
                    config.input_model_ref_strategy,
                    config.output_model_type,
                )
            except InputModelError as e:
                raise Error(str(e)) from e
            input_ = json.dumps(schema)
            if config.input_file_type == InputFileType.Auto:
                config.input_file_type = InputFileType.JsonSchema
        else:
            input_ = config.url or config.input or sys.stdin.read()

        run_generate_from_config(
            config=config,
            input_=input_,
            output=generate_output,
            extra_template_data=extra_template_data,
            aliases=aliases,
            command_line=shlex.join(["datamodel-codegen", *args]) if config.enable_command_header else None,
            custom_formatters_kwargs=custom_formatters_kwargs,
            settings_path=config.output,
            validators=validators_config,
            default_value_overrides=default_value_overrides,
        )
    except InvalidClassNameError as e:
        print(f"{e} You have to set `--class-name` option", file=sys.stderr)  # noqa: T201
        if temp_context is not None:
            temp_context.cleanup()
        return Exit.ERROR
    except Error as e:
        print(str(e), file=sys.stderr)  # noqa: T201
        if temp_context is not None:
            temp_context.cleanup()
        return Exit.ERROR
    except Exception:  # noqa: BLE001
        import traceback  # noqa: PLC0415

        print(traceback.format_exc(), file=sys.stderr)  # noqa: T201
        if temp_context is not None:
            temp_context.cleanup()
        return Exit.ERROR

    if config.check and config.output is not None and generate_output is not None:
        has_differences = False

        if is_directory_output:
            diffs, missing_files, extra_files = _compare_directories(generate_output, config.output, config.encoding)
            if diffs:
                print("".join(diffs), end="")  # noqa: T201
                has_differences = True
            for missing in missing_files:
                print(f"MISSING: {missing} (should be generated)")  # noqa: T201
                has_differences = True
            for extra in extra_files:
                print(f"EXTRA: {extra} (no longer generated)")  # noqa: T201
                has_differences = True
        else:
            diff_found, diff_lines = _compare_single_file(generate_output, config.output, config.encoding)
            if diff_found:
                print("".join(diff_lines), end="")  # noqa: T201
                has_differences = True

        if temp_context is not None:  # pragma: no branch
            temp_context.cleanup()

        return Exit.DIFF if has_differences else Exit.OK

    if config.watch:
        try:
            from datamodel_code_generator.watch import watch_and_regenerate  # noqa: PLC0415

            return watch_and_regenerate(
                config, extra_template_data, aliases, custom_formatters_kwargs, default_value_overrides
            )
        except Exception as e:  # noqa: BLE001
            print(str(e), file=sys.stderr)  # noqa: T201
            return Exit.ERROR

    return Exit.OK

Function: _build_module_edges
Domain: general
Explanation: Creates a dependency graph of modules based on their relative imports to facilitate correct execution order.
Docstring: Build dependency edges for topological sort.

    Returns edges where edges[u] contains v means u must come before v.
Source: def _build_module_edges(modules: dict[tuple[str, ...], str]) -> dict[tuple[str, ...], set[tuple[str, ...]]]:
    """Build dependency edges for topological sort.

    Returns edges where edges[u] contains v means u must come before v.
    """
    name_to_path: dict[str, tuple[str, ...]] = {}
    for path in modules:
        if (filepath := PurePath(path[-1])).suffix == ".py" and (name := filepath.stem) != "__init__":
            name_to_path[name] = path

    edges: dict[tuple[str, ...], set[tuple[str, ...]]] = {path: set() for path in modules}
    for path, code in modules.items():
        for imported in _get_relative_imports(code):
            if dep_path := name_to_path.get(imported):
                edges[dep_path].add(path)
    return edges

Function: _extract_models
Domain: general
Explanation: Filters a namespace dictionary to find all classes that are subclasses of Pydantic's BaseModel or Python's Enum, excluding the base classes themselves.
Docstring: Extract model and enum classes from namespace.
Source: def _extract_models(namespace: dict[str, Any]) -> dict[str, type]:
    """Extract model and enum classes from namespace."""
    return {
        k: v
        for k, v in namespace.items()
        if isinstance(v, type)
        and not k.startswith("_")
        and ((issubclass(v, BaseModel) and v is not BaseModel) or (issubclass(v, Enum) and v is not Enum))
    }

