Source: def get_model_by_path(
    schema: dict[str, YamlValue] | list[YamlValue], keys: list[str] | list[int]
) -> dict[str, YamlValue]:
    """Retrieve a model from schema by traversing the given path keys."""
    if not keys:
        if isinstance(schema, dict):
            return schema
        msg = f"Does not support json pointer to array. schema={schema}, key={keys}"
        raise NotImplementedError(msg)
    key = keys[0]
    if isinstance(key, str):
        key = unescape_json_pointer_segment(key)
    value = schema.get(str(key), {}) if isinstance(schema, dict) else schema[int(key)]
    if len(keys) == 1:
        if isinstance(value, dict):
            return value
        msg = f"Does not support json pointer to array. schema={schema}, key={keys}"
        raise NotImplementedError(msg)
    if isinstance(value, (dict, list)):
        return get_model_by_path(value, keys[1:])
    msg = f"Cannot traverse non-container value. schema={schema}, key={keys}"
    raise NotImplementedError(msg)

Function: validate_required
Domain: general
Explanation: Pydantic validator that normalizes the 'required' field in JSON Schema, handling string lists and complex nested logical objects.
Docstring: Validate and normalize required field values.
Source: @field_validator("required", mode="before")
def validate_required(cls, value: Any) -> Any:
    """Validate and normalize required field values."""
    if value is None:
        return []
    if isinstance(value, list):
        required_fields: list[str] = []
        for item in value:
            if isinstance(item, str):
                required_fields.append(item)
            elif isinstance(item, dict):
                for key, val in item.items():
                    if isinstance(val, list):
                        if key in {"anyOf", "oneOf"}:
                            continue
                        if key == "allOf":
                            required_fields.extend(sub_item for sub_item in val if isinstance(sub_item, str))
        value = required_fields
    return value

Function: get_data_type
Domain: general
Explanation: Core logic for converting a JSON Schema object into an internal DataType object, handling primitives, constraints, and overrides.
Docstring: Get the data type for a JSON Schema object.
Source: def get_data_type(self, obj: JsonSchemaObject) -> DataType:
    """Get the data type for a JSON Schema object."""
    python_type_override = self._get_python_type_override(obj)
    if python_type_override:
        return python_type_override
    if "const" in obj.extras:
        return self.data_type(literals=[obj.extras["const"]])
    if obj.type is None:
        return self.data_type_manager.get_data_type(Types.any,)
    def _get_data_type(type_: str, format__: str) -> DataType:
        if self.field_constraints:
            kwargs_to_pass = {}
            number_keys = ("minimum", "maximum", "exclusiveMinimum", "exclusiveMaximum")
            number_kwargs: dict[str, int | float | bool] = {}
            for key in number_keys:
                value = getattr(obj, key)
                if value is not None:
                    number_kwargs[key] = value.value if isinstance(value, UnionIntFloat) else value
            if self.data_type_manager.use_non_positive_negative_number_constrained_types:
                zero_bound_keys = [k for k, v in number_kwargs.items() if v == 0]
                if len(zero_bound_keys) == 1:
                    key = zero_bound_keys[0]
                    kwargs_to_pass = {key: number_kwargs[key]}
        else:
            kwargs_to_pass = obj.model_dump()
        return self.data_type_manager.get_data_type(self._get_type_with_mappings(type_, format__), field_constraints=self.field_constraints, **kwargs_to_pass,)
    if isinstance(obj.type, list):
        return self.data_type(data_types=[_get_data_type(t, obj.format or "default") for t in obj.type if t != "null"], is_optional="null" in obj.type,)
    data_type = _get_data_type(obj.type, obj.format or "default")
    if self.strict_nullable and obj.nullable:
        return self.data_type(data_types=[data_type], is_optional=True)
    return data_type

