Function: _format_current_options
Domain: general
Explanation: This function takes parsed CLI arguments and formats them into a clean string representation, excluding internal/utility options and handling different data types like booleans and lists for display.
Docstring: Format currently set CLI options.
Source: def _format_current_options(args: Namespace) -> str:
    """Format currently set CLI options."""
    lines: list[str] = []
    args_dict = vars(args)

    for key, value in sorted(args_dict.items()):
        if value is None:
            continue
        if key in PROMPT_EXCLUDED_OPTIONS:
            continue

        cli_key = key.replace("_", "-")

        if isinstance(value, bool):
            if value:
                lines.append(f"--{cli_key}")
        elif isinstance(value, list):
            formatted = " ".join(str(v) for v in value)
            lines.append(f"--{cli_key} {formatted}")
        else:
            lines.append(f"--{cli_key} {value}")

    return "\n".join(lines) if lines else "(No options specified)"

Function: get_relative_path
Domain: file_io
Explanation: Calculates the relative filesystem path from one directory to another, handling absolute and relative paths.
Docstring: Calculate relative path from base to target.
Source: def get_relative_path(base_path: PurePath, target_path: PurePath) -> PurePath:
    """Calculate relative path from base to target."""
    if base_path == target_path:
        return Path()
    if not target_path.is_absolute():
        return target_path
    parent_count: int = 0
    children: list[str] = []
    for base_part, target_part in zip_longest(base_path.parts, target_path.parts):
        if base_part == target_part and not parent_count:
            continue
        if base_part or not target_part:
            parent_count += 1
        if target_part:
            children.append(target_part)
    return Path(*[".." for _ in range(parent_count)], *children)

Function: get_valid_name
Domain: general
Explanation: Transforms a raw string from a schema into a valid Python identifier, ensuring it's not a keyword, doesn't start with numbers, and is unique within the given scope.
Docstring: Convert a name to a valid Python identifier.
Source:     def get_valid_name(
        self,
        name: str,
        excludes: set[str] | None = None,
        ignore_snake_case_field: bool = False,  # noqa: FBT001, FBT002
        upper_camel: bool = False,  # noqa: FBT001, FBT002
    ) -> str:
        """Convert a name to a valid Python identifier."""
        if not name:
            name = self.empty_field_name
        if name[0] == "#":
            name = name[1:] or self.empty_field_name

        if self.snake_case_field and not ignore_snake_case_field and self.original_delimiter is not None:
            name = snake_to_upper_camel(name, delimiter=self.original_delimiter)

        name = re.sub(r"[¹²³⁴⁵⁶⁷⁸⁹]|\W", "_", name)
        if name[0].isnumeric():
            name = f"{self.special_field_name_prefix}_{name}"

        # We should avoid having a field begin with an underscore, as it
        # causes pydantic to consider it as private
        while name.startswith("_"):
            if self.remove_special_field_name_prefix:
                name = name[1:]
            else:
                name = f"{self.special_field_name_prefix}{name}"
                break
        if self.capitalise_enum_members or (self.snake_case_field and not ignore_snake_case_field):
            name = camel_to_snake(name)
        count = 1
        validated_name = name.upper() if self.capitalise_enum_members else name
        if iskeyword(validated_name) or not self._validate_field_name(validated_name):
            name += "_"
        if upper_camel:
            new_name = snake_to_upper_camel(name)
        elif self.capitalise_enum_members:
            new_name = name.upper()
        else:
            new_name = name
        while (
            not new_name.isidentifier()
            or iskeyword(new_name)
            or (excludes and new_name in excludes)
            or not self._validate_field_name(new_name)
        ):
            new_name = f"{name}{count}" if upper_camel else f"{name}_{count}"
            count += 1
        return new_name

Function: get_type_base_name
Domain: general
Explanation: Uses AST to extract the base name of a Python type from a string representation.
Docstring: undefined
Source: def get_type_base_name(type_str: str) -> str:
    """Extract base type name from a type annotation string using AST.

    Examples:
        "List[str]" -> "List"
        "foo.bar.Baz" -> "Baz"
        "Optional[int]" -> "Optional"
    """
    try:
        tree = ast.parse(type_str, mode="eval")
    except SyntaxError:
        return type_str.split("[", maxsplit=1)[0].rsplit(".", 1)[-1].strip()

    body = tree.body
    if isinstance(body, ast.Subscript):
        body = body.value

    if isinstance(body, ast.Attribute):
        return body.attr
    if isinstance(body, ast.Name):
        return body.id
    return type_str.split("[", maxsplit=1)[0].rsplit(".", 1)[-1].strip()

Function: _remove_none_from_union
Domain: general
Explanation: A specialized string parser that removes 'None' from Union type annotations while handling nested brackets and constrained type syntax.
Docstring: undefined
Source: def _remove_none_from_union(type_: str, *, use_union_operator: bool) -> str:  # noqa: PLR0912
    """Remove None from a Union type string, handling nested unions."""
    if use_union_operator:
        if " | " not in type_:
            return type_
        separator = "|"
        inner_text = type_
    else:
        if not type_.startswith(UNION_PREFIX):
            return type_
        separator = ","
        inner_text = type_[len(UNION_PREFIX) : -1]

    parts = []
    inner_count = 0
    current_part = ""
    in_constr = 0

    for char in inner_text:
        current_part += char
        if char == "[" and in_constr == 0:
            inner_count += 1
        elif char == "]" and in_constr == 0:
            inner_count -= 1
        elif char == "(":
            if current_part.strip().startswith("constr(") and (len(current_part) < 2 or current_part[-2] != "\\"):  # noqa: PLR2004
                in_constr += 1
        elif char == ")":
            if in_constr > 0 and (len(current_part) < 2 or current_part[-2] != "\\"):  # noqa: PLR2004
                in_constr -= 1
        elif char == separator and inner_count == 0 and in_constr == 0:
            part = current_part[:-1].strip()
            if part != NONE:
                if not use_union_operator and part.startswith(UNION_PREFIX):
                    part = _remove_none_from_union(part, use_union_operator=False)
                parts.append(part)
            current_part = ""

    part = current_part.strip()
    if current_part and part != NONE:
        if not use_union_operator and part.startswith(UNION_PREFIX):  # pragma: no cover
            part = _remove_none_from_union(part, use_union_operator=False)
        parts.append(part)

    if not parts:
        return NONE
    if len(parts) == 1:
        return parts[0]

    if use_union_operator:
        return UNION_OPERATOR_DELIMITER.join(parts)

    return f"{UNION_PREFIX}{UNION_DELIMITER.join(parts)}]"

Function: DataType.type_hint
Domain: general
Explanation: Property that computes the final Python type annotation string for the DataType, considering flags like is_list, is_optional, and use_union_operator.
Docstring: undefined
Source:     @property
    def type_hint(self) -> str:  # noqa: PLR0912, PLR0915
        """Generate the Python type hint string for this DataType."""
        type_: str | None = self.alias or self.type
        if not type_:
            if self.is_tuple:
                tuple_type = STANDARD_TUPLE if self.use_standard_collections else TUPLE
                inner_types = [item.type_hint or ANY for item in self.data_types]
                type_ = f"{tuple_type}[{', '.join(inner_types)}]" if inner_types else f"{tuple_type}[()]"
            elif self.is_union:
                data_types: list[str] = []
                for data_type in self.data_types:
                    data_type_type = data_type.type_hint
                    if not data_type_type or data_type_type in data_types:
                        continue

                    if data_type_type == NONE:
                        self.is_optional = True
                        continue

                    non_optional_data_type_type = _remove_none_from_union(
                        data_type_type, use_union_operator=self.use_union_operator
                    )

                    if non_optional_data_type_type != data_type_type:
                        self.is_optional = True

                    data_types.append(non_optional_data_type_type)
                if not data_types:
                    type_ = ANY
                    self.import_ = self.import_ or IMPORT_ANY
                elif len(data_types) == 1:
                    type_ = data_types[0]
                elif self.use_union_operator:
                    type_ = UNION_OPERATOR_DELIMITER.join(data_types)
                else:
                    type_ = f"{UNION_PREFIX}{UNION_DELIMITER.join(data_types)}]"
                if self.discriminator:
                    type_ = f"Annotated[{type_}, Field(discriminator={self.discriminator!r})]"
            elif len(self.data_types) == 1:
                type_ = self.data_types[0].type_hint
            elif self.enum_member_literals:
                parts = [f"{enum_class}.{member}" for enum_class, member in self.enum_member_literals]
                type_ = f"{LITERAL}[{', '.join(parts)}]"
            elif self.literals:
                type_ = f"{LITERAL}[{', '.join(repr(literal) for literal in self.literals)}]"
            elif self.reference:
                type_ = self.reference.short_name
                type_ = self._get_wrapped_reference_type_hint(type_)
            else:
                type_ = ""
        if self.reference:
            source = self.reference.source
            is_alias = getattr(source, "is_alias", False)
            if isinstance(source, Nullable) and source.nullable and not is_alias:
                self.is_optional = True
        if self.is_frozen_set:
            set_ = STANDARD_FROZEN_SET if self.use_standard_collections else FROZEN_SET
            type_ = f"{set_}[{type_}]" if type_ else set_
        elif self.is_set:
            if self.use_generic_container:
                set_ = STANDARD_FROZEN_SET if self.use_standard_collections else FROZEN_SET
            elif self.use_standard_collections:
                set_ = STANDARD_SET
            else:  # pragma: no cover
                set_ = SET
            type_ = f"{set_}[{type_}]" if type_ else set_
        elif self.is_sequence:
            list_ = SEQUENCE
            type_ = f"{list_}[{type_}]" if type_ else list_
        elif self.is_list:
            if self.use_generic_container:
                list_ = SEQUENCE
            elif self.use_standard_collections:
                list_ = STANDARD_LIST
            else:
                list_ = LIST
            type_ = f"{list_}[{type_}]" if type_ else list_
        elif self.is_mapping:
            dict_ = MAPPING
            if self.dict_key or type_:
                key = self.dict_key.type_hint if self.dict_key else STR
                type_ = f"{dict_}[{key}, {type_ or ANY}]"
            else:  # pragma: no cover
                type_ = dict_
        elif self.is_dict:
            if self.use_generic_container:
                dict_ = MAPPING
            elif self.use_standard_collections:
                dict_ = STANDARD_DICT
            else:
                dict_ = DICT
            if self.dict_key or type_:
                key = self.dict_key.type_hint if self.dict_key else STR
                type_ = f"{dict_}[{key}, {type_ or ANY}]"
            else:  # pragma: no cover
                type_ = dict_
        if self.is_optional and type_ != ANY:
            return get_optional_type(type_, self.use_union_operator)
        if self.is_func and self.kwargs:
            kwargs: str = ", ".join(f"{k}={v}" for k, v in self.kwargs.items())
            return f"{type_}({kwargs})"
        return type_
